using UnityEngine;
using UnityEngine.Events;

/// <summary>
/// Mola: ao ser pisada por cima, lança o player para cima com força fixa
/// (add-on opcional — combina com MovingPlatform/PlatformSpinner, etc).
/// </summary>
[RequireComponent(typeof(Collider2D))]
[DisallowMultipleComponent]
public class SpringPlatform : MonoBehaviour
{
    [Tooltip("Velocidade vertical aplicada ao player ao pisar na mola (substitui a velocidade Y actual).")]
    [Min(0f)] public float forcaImpulso = 16f;

    [Tooltip("Também afecta inimigos (com Rigidbody2D) que pisem na mola, não só o player.")]
    public bool afectaInimigos = false;

    [Tooltip("Tempo mínimo (segundos) entre dois impulsos consecutivos ao mesmo objecto.")]
    [Min(0f)] public float cooldown = 0.1f;

    [Header("Eventos")]
    public UnityEvent onImpulsionou;

    private Collider2D _col;
    private float _nextTime;

    private void Awake()
    {
        _col = GetComponent<Collider2D>();
    }

    private void OnCollisionEnter2D(Collision2D collision) => TryLaunch(collision);
    private void OnCollisionStay2D(Collision2D collision) => TryLaunch(collision);

    private void TryLaunch(Collision2D collision)
    {
        if (Time.time < _nextTime) return;

        bool isPlayer = collision.collider.CompareTag("Player");
        if (!isPlayer && !afectaInimigos) return;
        if (!isPlayer && collision.collider.GetComponent<EnemyController>() == null) return;

        var rb = collision.rigidbody;
        if (rb == null) return;

        // Só impulsiona se estiver a pisar a mola por cima (não de lado/baixo).
        if (collision.collider.bounds.min.y < _col.bounds.max.y - 0.15f) return;

        rb.velocity = new Vector2(rb.velocity.x, forcaImpulso);
        _nextTime = Time.time + cooldown;

        onImpulsionou?.Invoke();
    }
}
